import { CustomField } from '@brandembassy/ts-types-platform/dist/customField/CustomField';

import { ChatSDKError } from '../error/ChatSDKError';
import { getCustomFieldMaxLengthErrorMessage } from '../error/errorMessages';
import { isUndefined } from '../utils/is';

type Ident = CustomField['ident'];
type Value = CustomField['value'];

export type CustomFieldsObject = Record<Ident, Value>;
export type CustomFieldsMap = Map<Ident, Value>;

const MAX_CUSTOM_FIELD_LENGTH = 1024;

export function setCustomFields(
  fields: CustomFieldsMap,
  set: CustomFieldsObject = {},
): void {
  for (const ident of Object.keys(set)) {
    validateCustomField(ident, set[ident]);
    fields.set(ident, set[ident]);
  }
}

export function setCustomFieldsFromArray(
  fields: CustomFieldsMap,
  set: Array<CustomField> = [],
): void {
  for (const { ident, value } of set) {
    validateCustomField(ident, value);
    fields.set(ident, value);
  }
}

export function setCustomField(
  fields: CustomFieldsMap,
  ident: Ident,
  value: CustomField['value'],
): void {
  validateCustomField(ident, value);
  fields.set(ident, value);
}

export function getCustomFields(fields: CustomFieldsMap): CustomFieldsObject {
  return Object.fromEntries(fields);
}

export function getCustomFieldsArray(
  fields: CustomFieldsMap,
): Array<CustomField> {
  return Array.from(fields).map<CustomField>(([ident, value]) => ({
    ident,
    value,
  }));
}

export function removeCustomField(fields: CustomFieldsMap, ident: Ident): void {
  fields.delete(ident);
}

export function getCustomFieldsFromArray(
  fields: Array<CustomField>,
): CustomFieldsObject {
  return Object.fromEntries(fields.map((field) => [field.ident, field.value]));
}

function validateCustomField(ident: Ident, value: Value): void {
  if (isUndefined(ident) || isUndefined(value)) {
    throw new ChatSDKError('Custom field name and value must be set');
  }

  if (!isCustomFieldValueValid(value)) {
    throw new ChatSDKError(
      getCustomFieldMaxLengthErrorMessage(ident, MAX_CUSTOM_FIELD_LENGTH),
    );
  }
}

function isCustomFieldValueValid(value: Value): boolean {
  if (value === null) {
    return true;
  }
  if (typeof value === 'string') {
    return value.length <= MAX_CUSTOM_FIELD_LENGTH;
  }

  return false;
}
