import { PersistentMenuItem } from '@brandembassy/ts-types-chat/dist/persistentMenu/PersistentMenuItem';
import { BrandId } from '@brandembassy/ts-types-platform/dist/brand/BrandId';
import { ChannelId } from '@brandembassy/ts-types-platform/dist/channel/ChannelId';

import { ChatSDKError } from '../error/ChatSDKError';
import { getDefaultHeaders } from '../request/defaultHeaders';
import { NetworkRequestMetadata } from '../request/NetworkRequestMetadata';
import { getJSON } from '../utils/fetchJSON';

export async function fetchPersistentMenuItems(
  brandId: BrandId,
  channelId: ChannelId,
  chatEndpoint: string,
  requestMetadataHttpHeaders: NetworkRequestMetadata['httpHeaders'] = {},
  callerServiceId?: string,
): Promise<Array<PersistentMenuItem>> {
  const resource = `${chatEndpoint}/chat/1.0/brand/${encodeURIComponent(
    String(brandId),
  )}/channel/${encodeURIComponent(String(channelId))}/persistent-menu-items`;
  const options = {
    headers: {
      ...getDefaultHeaders(requestMetadataHttpHeaders, callerServiceId),
    },
  };

  let response: unknown;
  try {
    response = await getJSON<unknown>(resource, options, callerServiceId);
  } catch (error) {
    throw new ChatSDKError('Failed to fetch persistent menu items.', { error });
  }

  if (!Array.isArray(response)) {
    throw new ChatSDKError('Persistent menu items response is not an array.', {
      response,
    });
  }

  return response as Array<PersistentMenuItem>;
}
