import { VisitorId } from '@brandembassy/ts-types-platform/dist/visitor/VisitorId';

import { SDKVariableStorage } from '../variables/VariableStorage';

const VISITOR_ID_STORAGE_KEY = 'visitorId';

export function storeVisitorId(visitorId: VisitorId): void {
  if (SDKVariableStorage.STORAGE) {
    SDKVariableStorage.STORAGE.setItem(VISITOR_ID_STORAGE_KEY, visitorId);
  }
}

export function getStoredVisitorId(): VisitorId | null {
  return SDKVariableStorage.STORAGE
    ? SDKVariableStorage.STORAGE.getItem(VISITOR_ID_STORAGE_KEY)
    : null;
}
