import { MessageType } from '@brandembassy/ts-types-platform/dist/message/MessageType';

import { StreamedMessageEventData } from './StreamedMessageEventData';

export const isStreamedMessageEventData = (
  eventData: unknown,
): eventData is StreamedMessageEventData => {
  const streamedEventData = eventData as StreamedMessageEventData;

  return (
    streamedEventData?.originalMessage?.messageContent?.type ===
      MessageType.STREAMED && typeof streamedEventData?.fullContent === 'string'
  );
};
