import { StreamedPayload } from '@brandembassy/ts-types-platform/dist/message/StreamedPayload';

export const SUPPORTED_PROTOCOL = 'sse';

export interface ValidStreamedPayload extends StreamedPayload {
  readonly protocol: typeof SUPPORTED_PROTOCOL;
  readonly sourceUrl: string;
}

export function isValidStreamedPayload(
  payload: StreamedPayload,
): payload is ValidStreamedPayload {
  return (
    payload.protocol === SUPPORTED_PROTOCOL &&
    typeof payload.sourceUrl === 'string' &&
    payload.sourceUrl.length > 0
  );
}
