import { MessageCreatedData } from '@brandembassy/ts-types-chat/dist/pushUpdate/MessageCreatedEvent';
import { PushUpdateEventType } from '@brandembassy/ts-types-chat/dist/pushUpdate/PushUpdateEventType';
import { StreamedMessageContent } from '@brandembassy/ts-types-platform/dist/message/MessageContent';
import { MessageType } from '@brandembassy/ts-types-platform/dist/message/MessageType';

import { ChatEventData } from '../../ChatEvent';

export interface StreamedMessageCreatedEvent extends ChatEventData {
  data: MessageCreatedData & {
    message: MessageCreatedData['message'] & {
      messageContent: StreamedMessageContent;
    };
  };
  type: PushUpdateEventType.MESSAGE_CREATED;
}

export function isStreamedMessageContent(
  event: ChatEventData,
): event is StreamedMessageCreatedEvent {
  if (event.type !== PushUpdateEventType.MESSAGE_CREATED) {
    return false;
  }

  const data = event.data as MessageCreatedData;

  return data?.message?.messageContent?.type === MessageType.STREAMED;
}
