export function isValidServerStreamedDelta(parsed: unknown): parsed is {
  delta: { content: string; finish_reason: string | null };
} {
  return (
    typeof parsed === 'object' &&
    parsed !== null &&
    'delta' in parsed &&
    typeof (parsed as Record<string, unknown>).delta === 'object' &&
    typeof (parsed as Record<string, Record<string, unknown>>).delta
      ?.content === 'string'
  );
}
