import { AbortError } from '../error/AbortError';
import { ChatSDKError } from '../error/ChatSDKError';
import { getDefaultHeaders } from '../request/defaultHeaders';

import {
  buildFailureContext,
  buildResponseError,
  getRequestMethod,
  runFetchAttempts,
} from './fetchHelpers';
import { getNetworkInfo } from './getNetworkInfo';
import { isWindowClosing, registerWindowUnload } from './isWindowClosing';

const FETCH_ABORTED_DUE_TO_TIMEOUT = 'Fetch aborted due to timeout';
const FETCH_ABORTED_WINDOW_CLOSING =
  'Fetch aborted because the window is closing';

export interface FetchOptions extends Omit<RequestInit, 'headers'> {
  /**
   * Additional headers
   */
  headers?: Record<string, string>;
  /**
   * Request timeout in milliseconds. When set, the request will be aborted and
   * a ChatSDKError will be thrown if it does not complete within this time.
   * The timeout covers the entire call including any retries. When not set, no
   * timeout is applied.
   */
  timeout?: number;
}

async function abortableFetch(
  resource: RequestInfo,
  options?: FetchOptions,
  callerServiceId?: string,
): Promise<Response> {
  const { signal, headers, timeout, ...restOptions } = options || {};

  const abortController = new AbortController();

  const onAbort = () => {
    abortController.abort(new AbortError('Fetch aborted by signal'));
  };

  if (signal) {
    signal.addEventListener('abort', onAbort, { once: true });
  }

  let timeoutId: ReturnType<typeof setTimeout> | undefined;

  if (timeout !== undefined) {
    timeoutId = setTimeout(() => {
      abortController.abort(new AbortError(FETCH_ABORTED_DUE_TO_TIMEOUT));
    }, timeout);
  }

  const requestInit = {
    headers: {
      ...getDefaultHeaders(headers, callerServiceId),
    },
    signal: abortController.signal,
    ...restOptions,
  };

  registerWindowUnload();

  if (isWindowClosing()) {
    throw new AbortError(FETCH_ABORTED_WINDOW_CLOSING);
  }

  const requestTimeStart = Date.now();
  let lastAttemptPerformanceStart = performance.now();
  const method = getRequestMethod(requestInit);

  try {
    const lastResponse = await runFetchAttempts({
      resource,
      requestInit,
      abortController,
      method,
      onAttemptStart: () => {
        lastAttemptPerformanceStart = performance.now();
      },
    });

    if (lastResponse.ok) {
      return lastResponse;
    }

    throw await buildResponseError(lastResponse, {
      performanceTimeStart: lastAttemptPerformanceStart,
      requestInit,
      requestTimeStart,
      resource,
    });
  } catch (error) {
    if (
      error instanceof AbortError &&
      error.message.includes(FETCH_ABORTED_DUE_TO_TIMEOUT)
    ) {
      throw new ChatSDKError('Request timed out', {
        ...buildFailureContext(lastAttemptPerformanceStart, error),
        networkInfo: getNetworkInfo(),
        requestDuration: Date.now() - requestTimeStart,
        requestOptions: requestInit,
        requestUrl: resource,
        timeout,
      });
    }

    if (abortController.signal.aborted || isWindowClosing()) {
      throw new AbortError('Fetch aborted');
    }

    if (error instanceof ChatSDKError) {
      throw error;
    }

    throw new ChatSDKError(error, {
      ...buildFailureContext(lastAttemptPerformanceStart, error),
      errorMessage: error instanceof Error ? error.message : String(error),
      errorName: error instanceof Error ? error.name : typeof error,
      networkInfo: getNetworkInfo(),
      requestDuration: Date.now() - requestTimeStart,
      requestOptions: requestInit,
      requestUrl: resource,
    });
  } finally {
    clearTimeout(timeoutId);
    signal?.removeEventListener('abort', onAbort);
  }
}

/**
 * Make a request and parse the response as JSON, otherwise throws the response or error
 *
 * GET requests are automatically retried up to `MAX_FETCH_ATTEMPTS` times on
 * network-level failures (a `TypeError` from `fetch`) with exponential backoff
 * and jitter. HTTP error responses (4xx, 5xx, 429) are NOT retried. Non-GET
 * requests are attempted exactly once.
 *
 * @throws Response - If the response status is not ok
 * @throws AbortError - The request was aborted
 * @throws NotAllowedError
 * @throws TypeError
 * @throws DOMException - The request was aborted
 * @throws SyntaxError - The response body cannot be parsed as JSON
 */
export async function fetchJSON<T = unknown>(
  resource: RequestInfo,
  options?: FetchOptions,
  callerServiceId?: string,
): Promise<T> {
  const response = await abortableFetch(resource, options, callerServiceId);

  return response.json();
}

/**
 * Make a GET request
 *
 * Retries network-level failures (`TypeError` from `fetch`) up to
 * `MAX_FETCH_ATTEMPTS` times with exponential backoff and jitter. HTTP error
 * responses are not retried.
 *
 * @throws Response - If the response status is not ok
 * @throws AbortError - The request was aborted
 * @throws NotAllowedError
 * @throws TypeError
 * @throws DOMException - The request was aborted
 * @throws SyntaxError - The response body cannot be parsed as JSON
 */
export async function getJSON<T = unknown>(
  resource: RequestInfo,
  options?: FetchOptions,
  callerServiceId?: string,
): Promise<T> {
  return fetchJSON(resource, { method: 'GET', ...options }, callerServiceId);
}

/**
 * Make a POST request with JSON body
 *
 * @throws Response - If the response status is not ok
 * @throws AbortError - The request was aborted
 * @throws NotAllowedError
 * @throws TypeError
 * @throws DOMException - The request was aborted
 * @throws SyntaxError - The response body cannot be parsed as JSON
 */
export async function postJSON<T = unknown>(
  resource: RequestInfo,
  body: unknown,
  options?: FetchOptions,
  callerServiceId?: string,
): Promise<T> {
  return fetchJSON(
    resource,
    {
      method: 'POST',
      body: JSON.stringify(body ?? {}),
      ...options,
    },
    callerServiceId,
  );
}
