export type ProbableFetchCause =
  | 'browser-blocked'
  | 'http-4xx'
  | 'http-5xx'
  | 'network-failure'
  | 'offline'
  | 'unknown'
  | 'user-aborted';

export interface ChatSDKErrorData {
  [key: string]: unknown;
  /**
   * performance.now() delta from before the fetch() call to the catch.
   * Populated for fetch-originated errors only.
   */
  elapsedMs?: number;
  /**
   * Use for wrap original error cased by this error
   */
  error?: unknown;
  /**
   * navigator.onLine at the time of failure. `'unknown'` when navigator.onLine
   * was not readable. Populated for fetch-originated errors only.
   */
  navigatorOnLine?: boolean | 'unknown';
  /**
   * Categorical bucket for fetch-failure triage. Populated for fetch-
   * originated errors only.
   */
  probableCause?: ProbableFetchCause;
}

const UNKNOWN_ERROR_MESSAGE = 'Unknown error';

export class ChatSDKError extends Error {
  name: string = 'ChatSDKError';
  data: unknown;
  additionalInfo?: unknown;

  constructor(error: unknown, data?: ChatSDKErrorData) {
    super();

    if (error instanceof ChatSDKError) {
      this.#initializeFromError(error);
      this.additionalInfo = data;

      return;
    }

    if (data?.error instanceof ChatSDKError) {
      const { error: nestedError, ...restData } = data;
      this.#initializeFromError(nestedError);
      this.additionalInfo = this.#mergeAdditionalInfo(
        nestedError.additionalInfo,
        restData,
      );

      const baseMessage = this.#formatBaseMessage(error);
      const innerMessage = this.#stripNamePrefix(nestedError.message);
      this.message = innerMessage
        ? `${baseMessage} (caused by: ${innerMessage})`
        : baseMessage;

      return;
    }

    this.data = data;

    if (typeof error === 'string') {
      this.message = `[${this.name}]: ${error}`;
    } else if (error instanceof Error) {
      this.message = `[${this.name}]: ${error.message}`;
      this.cause = error;
      this.stack = error.stack;
      this.additionalInfo = data;
    } else if (error !== undefined) {
      this.message = `[${this.name}]: ${UNKNOWN_ERROR_MESSAGE}`;
      this.additionalInfo = { _thrownValue: error };
    }

    if (data?.error instanceof Error) {
      this.cause = data.error;
      this.message = `${this.message} (caused by: ${data.error.message})`;
    }
  }

  #initializeFromError(error: ChatSDKError): void {
    this.message = error.message;
    this.stack = error.stack;
    this.cause = this.#isDirectChatSDKError(error) ? error.cause : error;
    this.data = error.data;
  }

  #formatBaseMessage(error: unknown): string {
    if (typeof error === 'string') {
      return `[${this.name}]: ${error}`;
    }
    if (error instanceof Error) {
      return `[${this.name}]: ${error.message}`;
    }

    return `[${this.name}]: ${UNKNOWN_ERROR_MESSAGE}`;
  }

  #stripNamePrefix(message: string): string {
    const prefix = `[${this.name}]: `;

    return message.startsWith(prefix) ? message.slice(prefix.length) : message;
  }

  #mergeAdditionalInfo(inner: unknown, rest: Record<string, unknown>): unknown {
    const innerObj =
      inner !== null && typeof inner === 'object'
        ? (inner as Record<string, unknown>)
        : {};
    const merged = { ...innerObj, ...rest };

    return Object.keys(merged).length === 0 ? undefined : merged;
  }

  /**
   * Checks if the value is direct ChatSDKError not a subclass.
   */
  #isDirectChatSDKError(value: unknown): value is ChatSDKError {
    return value instanceof ChatSDKError && value.constructor === ChatSDKError;
  }
}
