import { SDKVariableStorage } from '../variables/VariableStorage';

import { TransactionTokenResponse } from './TransactionToken';

const TRANSACTION_TOKEN_CACHE_KEY = 'TTR';

export const getCachedTransactionTokenResponse =
  (): TransactionTokenResponse | null => {
    if (!SDKVariableStorage.CACHE_STORAGE) {
      return null;
    }

    return SDKVariableStorage.CACHE_STORAGE.getItem(
      TRANSACTION_TOKEN_CACHE_KEY,
    );
  };

export const cacheTransactionTokenResponse = (
  response: TransactionTokenResponse,
  expiresIn: number,
): void => {
  if (!SDKVariableStorage.CACHE_STORAGE) {
    return;
  }

  SDKVariableStorage.CACHE_STORAGE.setItem(
    TRANSACTION_TOKEN_CACHE_KEY,
    response,
    expiresIn * 1000,
  );
};

export const clearCachedTransactionTokenResponse = (): void => {
  if (!SDKVariableStorage.CACHE_STORAGE) {
    return;
  }

  SDKVariableStorage.CACHE_STORAGE.removeItem(TRANSACTION_TOKEN_CACHE_KEY);
};
