import { VisitorId } from '@brandembassy/ts-types-platform/dist/visitor/VisitorId';

import { generateId } from '../utils/generateId';

import { getStoredVisitorId, storeVisitorId } from './visitorIdStorage';

export function resolveVisitorId(visitorId?: VisitorId): VisitorId {
  return visitorId ?? getStoredVisitorId() ?? generateId();
}

export function resolveAndPersistVisitorId(visitorId?: VisitorId): VisitorId {
  const resolvedVisitorId = resolveVisitorId(visitorId);
  storeVisitorId(resolvedVisitorId);

  return resolvedVisitorId;
}
