import { AbortError } from '../error/AbortError';
import { ChatSDKError, ProbableFetchCause } from '../error/ChatSDKError';
import { SdkVersionNotSupported } from '../error/SdkVersionNotSupported';
import { isSdkVersionNotSupportedEvent } from '../event/middleware/sdkVersionCheck';
import { getErrorResponseData } from '../request/getErrorResponseData';

import { deriveProbableCause } from './deriveProbableCause';
import { getNetworkInfo } from './getNetworkInfo';
import { isWindowClosing } from './isWindowClosing';

/**
 * Maximum total fetch attempts (initial attempt plus retries) for retryable
 * GET requests. Non-idempotent methods (POST, PATCH, DELETE, ...) are always
 * attempted exactly once regardless of this value.
 *
 * Retries only kick in for true network-level failures (`TypeError` from
 * `fetch`). HTTP error responses — including 429 and 5xx — are never retried
 * because the server has already chosen to refuse the request; retrying can
 * make rate-limiting worse and is not safe in general.
 */
export const MAX_FETCH_ATTEMPTS = 5;

/** Base delay used to compute exponential backoff between retry attempts. */
const RETRY_BASE_DELAY_MS = 200;

export interface FailureContext {
  elapsedMs: number;
  navigatorOnLine: boolean | 'unknown';
  probableCause: ProbableFetchCause;
}

export interface RunFetchAttemptsArgs {
  abortController: AbortController;
  method: string;
  onAttemptStart: () => void;
  requestInit: RequestInit;
  resource: RequestInfo;
}

/**
 * Executes the fetch with bounded retries on network-level failures.
 * Returns the Response (ok or not — HTTP error statuses are returned, not
 * retried). Throws on AbortError, on a non-retryable thrown error, or after
 * exhausting retries with a persistent network TypeError.
 */
export async function runFetchAttempts({
  resource,
  requestInit,
  abortController,
  method,
  onAttemptStart,
}: RunFetchAttemptsArgs): Promise<Response> {
  const maxAttempts = method === 'GET' ? MAX_FETCH_ATTEMPTS : 1;

  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
    if (abortController.signal.aborted || isWindowClosing()) {
      throw new AbortError('Fetch aborted');
    }

    onAttemptStart();

    try {
      return await fetch(resource, requestInit);
    } catch (error) {
      if (
        attempt >= maxAttempts ||
        !isRetryableThrownError(error, method, abortController.signal)
      ) {
        throw error;
      }

      await abortableDelay(
        computeBackoffDelay(attempt),
        abortController.signal,
      );
    }
  }

  throw new ChatSDKError('Fetch failed without producing a response');
}

export interface BuildResponseErrorArgs {
  performanceTimeStart: number;
  requestInit: RequestInit;
  requestTimeStart: number;
  resource: RequestInfo;
}

/**
 * Inspect a non-ok Response and return the matching SDK error. Returns the
 * error rather than throwing so the caller can `throw` it directly, which
 * keeps control flow obvious at the call site.
 */
export async function buildResponseError(
  response: Response,
  ctx: BuildResponseErrorArgs,
): Promise<ChatSDKError | SdkVersionNotSupported> {
  const errorResponseData = await getErrorResponseData(response);

  if (isSdkVersionNotSupportedEvent(errorResponseData)) {
    return new SdkVersionNotSupported();
  }

  return new ChatSDKError(`Request failed with status ${response.status}`, {
    ...buildFailureContext(
      ctx.performanceTimeStart,
      undefined,
      response.status,
    ),
    errorResponseData,
    networkInfo: getNetworkInfo(),
    requestDuration: Date.now() - ctx.requestTimeStart,
    requestOptions: ctx.requestInit,
    requestUrl: ctx.resource,
    responseStatus: response.status,
    responseStatusText: response.statusText,
  });
}

/**
 * Snapshot information used to enrich a ChatSDKError after a fetch failure.
 * `performanceTimeStart` should be the `performance.now()` value captured at
 * the start of the LAST fetch attempt so `elapsedMs` reflects that attempt
 * (not the whole retry sequence) — this keeps probableCause classification
 * correct.
 */
export function buildFailureContext(
  performanceTimeStart: number,
  error?: unknown,
  responseStatus?: number,
): FailureContext {
  const elapsedMs = performance.now() - performanceTimeStart;
  const navigatorOnLine = readNavigatorOnLine();

  return {
    elapsedMs,
    navigatorOnLine,
    probableCause: deriveProbableCause({
      elapsedMs,
      error,
      navigatorOnLine,
      responseStatus,
    }),
  };
}

export function getRequestMethod(init: RequestInit): string {
  return (init.method ?? 'GET').toUpperCase();
}

function isRetryableThrownError(
  error: unknown,
  method: string,
  signal: AbortSignal,
): boolean {
  if (signal.aborted || isWindowClosing()) {
    return false;
  }

  return method === 'GET' && error instanceof TypeError;
}

function computeBackoffDelay(attemptIndex: number): number {
  const exponential = RETRY_BASE_DELAY_MS * Math.pow(2, attemptIndex - 1);
  const jitter = Math.random() * RETRY_BASE_DELAY_MS;

  return exponential + jitter;
}

function abortableDelay(ms: number, signal: AbortSignal): Promise<void> {
  return new Promise<void>((resolve, reject) => {
    if (signal.aborted) {
      reject(getAbortReason(signal));

      return;
    }

    const onAbort = (): void => {
      clearTimeout(timerId);
      reject(getAbortReason(signal));
    };

    const timerId = setTimeout(() => {
      signal.removeEventListener('abort', onAbort);
      resolve();
    }, ms);

    signal.addEventListener('abort', onAbort, { once: true });
  });
}

function getAbortReason(signal: AbortSignal): Error {
  if (signal.reason instanceof Error) {
    return signal.reason;
  }

  return new AbortError('Fetch aborted by signal');
}

function readNavigatorOnLine(): boolean | 'unknown' {
  try {
    return navigator.onLine;
  } catch {
    return 'unknown';
  }
}
