import { SenderTypingStartedData } from '@brandembassy/ts-types-chat/dist/pushUpdate/SenderTypingStartedEvent';

import { ChatEvent, ChatEventData } from '../event/ChatEvent';

function isOutbound(data: unknown): boolean {
  return (data as SenderTypingStartedData)?.direction === 'outbound';
}

export function agentTypingStarted(event: ChatEventData): ChatEventData {
  if (isOutbound(event.data)) {
    return {
      ...event,
      type: ChatEvent.AGENT_TYPING_STARTED,
    };
  }

  return event;
}

export function agentTypingEnded(event: ChatEventData): ChatEventData {
  if (isOutbound(event.data)) {
    return {
      ...event,
      type: ChatEvent.AGENT_TYPING_ENDED,
    };
  }

  return event;
}
