import { MessageCreatedData } from '@brandembassy/ts-types-chat/dist/pushUpdate/MessageCreatedEvent';
import { MessageId } from '@brandembassy/ts-types-platform/dist/message/MessageId';
import { StreamedPayload } from '@brandembassy/ts-types-platform/dist/message/StreamedPayload';

import { generateId } from '../../../utils/generateId';
import { ChatCustomEvent, ChatEvent, ChatEventData } from '../../ChatEvent';
import { EventMiddleware } from '../../ChatEventMiddleware';
import { IChatEventTarget } from '../../ChatEventTarget';

import { isStreamedMessageContent } from './isStreamedMessageContent';
import { isValidServerStreamedDelta } from './isValidServerStreamedDelta';
import { isValidStreamedPayload } from './isValidStreamedPayload';
import { StreamedMessageEventData } from './StreamedMessageEventData';

export class StreamedMessageHandler {
  readonly #messageEmitter: IChatEventTarget;
  readonly #activeConnections = new Map<MessageId, EventSource>();
  readonly #accumulatedContent = new Map<MessageId, string>();

  constructor(messageEmitter: IChatEventTarget) {
    this.#messageEmitter = messageEmitter;
  }

  // -- Connection management --

  #hasConnection(messageId: MessageId): boolean {
    return this.#activeConnections.has(messageId);
  }

  #addConnection(messageId: MessageId, eventSource: EventSource): void {
    this.#activeConnections.set(messageId, eventSource);
  }

  #closeConnection(messageId: MessageId): void {
    this.#activeConnections.get(messageId)?.close();
    this.#activeConnections.delete(messageId);
  }

  #getAllConnections(): Array<MessageId> {
    return [...this.#activeConnections.keys()];
  }

  // -- Accumulated content management --

  #initContent(messageId: MessageId): void {
    this.#accumulatedContent.set(messageId, '');
  }

  #getContent(messageId: MessageId): string {
    return this.#accumulatedContent.get(messageId) ?? '';
  }

  #appendContent(messageId: MessageId, chunk: string): string {
    const newContent = this.#getContent(messageId) + chunk;

    this.#accumulatedContent.set(messageId, newContent);

    return newContent;
  }

  #removeContent(messageId: MessageId): void {
    this.#accumulatedContent.delete(messageId);
  }

  // -- Streaming --

  #startStreaming(
    messageId: MessageId,
    message: MessageCreatedData['message'],
    payload: StreamedPayload,
  ): void {
    this.#initContent(messageId);

    const eventSource = new EventSource(payload.sourceUrl);

    this.#addConnection(messageId, eventSource);

    this.#dispatch(ChatEvent.STREAMED_MESSAGE_STARTED, message, {
      fullContent: '',
    });

    const handleSSEMessage = (sseEvent: MessageEvent): void => {
      try {
        const parsed: unknown = JSON.parse(sseEvent.data);

        // Skip non-conforming messages (e.g., heartbeats, metadata)
        if (!isValidServerStreamedDelta(parsed)) {
          return;
        }

        const { delta } = parsed;
        const newContent = this.#appendContent(messageId, delta.content);

        if (delta.finish_reason === 'stop') {
          this.#dispatch(ChatEvent.STREAMED_MESSAGE_COMPLETED, message, {
            delta: { content: delta.content },
            fullContent: newContent,
          });

          this.#cleanup(messageId);
        } else {
          this.#dispatch(ChatEvent.STREAMED_MESSAGE_DELTA, message, {
            delta: { content: delta.content },
            fullContent: newContent,
          });
        }
      } catch {
        this.#dispatch(ChatEvent.STREAMED_MESSAGE_FAILED, message, {
          fullContent: this.#getContent(messageId),
        });

        this.#cleanup(messageId);
      }
    };

    // Listen for named 'delta' events (SSE `event: delta` field)
    eventSource.addEventListener('delta', handleSSEMessage);
    // Also listen for unnamed events as fallback (SSE messages without `event:` field)
    eventSource.onmessage = handleSSEMessage;

    eventSource.onerror = (): void => {
      // readyState 0 (CONNECTING) means EventSource is attempting to reconnect.
      // Only treat as a failure if the connection has been explicitly closed (readyState 2)
      // or if no content has been received (readyState 0 after open = immediate failure).
      if (
        eventSource.readyState === EventSource.CLOSED ||
        !this.#hasConnection(messageId)
      ) {
        this.#dispatch(ChatEvent.STREAMED_MESSAGE_FAILED, message, {
          fullContent: this.#getContent(messageId),
        });

        this.#cleanup(messageId);
      }
    };
  }

  // -- Lifecycle --

  #cleanup(messageId: MessageId): void {
    this.#closeConnection(messageId);
    this.#removeContent(messageId);
  }

  readonly middleware: EventMiddleware = (
    eventData: ChatEventData,
  ): ChatEventData | null => {
    if (!isStreamedMessageContent(eventData)) {
      return eventData;
    }

    const { message } = eventData.data;
    const payload = message.messageContent.payload;

    if (!isValidStreamedPayload(payload)) {
      this.#dispatch(ChatEvent.STREAMED_MESSAGE_FAILED, message, {
        fullContent: '',
      });

      return null;
    }

    const messageId = message.id;

    // Close any existing connection for this message (e.g., duplicate delivery after reconnect)
    if (this.#hasConnection(messageId)) {
      this.#cleanup(messageId);
    }

    this.#startStreaming(messageId, message, payload);

    // Swallow the original MESSAGE_CREATED event
    return null;
  };

  destroy(): void {
    for (const messageId of this.#getAllConnections()) {
      this.#cleanup(messageId);
    }
  }

  #dispatch(
    type: string,
    message: MessageCreatedData['message'],
    streamedData: Omit<
      StreamedMessageEventData,
      'messageId' | 'threadId' | 'originalMessage'
    >,
  ): void {
    const eventData: ChatEventData = {
      id: generateId(),
      createdAt: new Date().toISOString(),
      data: {
        messageId: message.id,
        threadId: String(message.threadIdOnExternalPlatform),
        originalMessage: message,
        ...streamedData,
      } as StreamedMessageEventData,
    };

    this.#messageEmitter.dispatchEvent(
      new ChatCustomEvent(type, { detail: eventData }),
    );
  }
}
