import { ProbableFetchCause } from '../error/ChatSDKError';

// DNS, TCP and TLS cannot complete this fast, so a sub-threshold TypeError
// indicates the browser refused before bytes left (extension, CSP,
// mixed-content, or same-origin-policy denial).
const PROBABLE_BLOCKED_THRESHOLD_MS = 50;

export interface DeriveProbableCauseArgs {
  elapsedMs: number;
  error?: unknown;
  navigatorOnLine: boolean | 'unknown';
  responseStatus?: number;
}

export function deriveProbableCause({
  elapsedMs,
  error,
  navigatorOnLine,
  responseStatus,
}: DeriveProbableCauseArgs): ProbableFetchCause {
  if (responseStatus !== undefined) {
    if (responseStatus >= 400 && responseStatus < 500) {
      return 'http-4xx';
    }
    if (responseStatus >= 500 && responseStatus < 600) {
      return 'http-5xx';
    }
  }

  const errorName =
    error !== null && typeof error === 'object' && 'name' in error
      ? (error as { name?: unknown }).name
      : undefined;

  if (errorName === 'AbortError') {
    return 'user-aborted';
  }

  if (errorName === 'TypeError') {
    if (elapsedMs < PROBABLE_BLOCKED_THRESHOLD_MS) {
      return 'browser-blocked';
    }
    // Only claim 'offline' when we explicitly know navigator.onLine is false;
    // 'unknown' falls through to network-failure rather than misreporting.
    if (navigatorOnLine === false) {
      return 'offline';
    }

    return 'network-failure';
  }

  return 'unknown';
}
